export function parseArgs(argv) {
  const result = { _: [] }
  let lastIndex = -1

  for (let index = 0; index < argv.length; index += 1) {
    const arg = argv[index]
    if (arg.startsWith('-')) {
      lastIndex = index
      result[arg.slice(2)] = true
    } else if (index - 1 === lastIndex) {
      result[arg.slice(2)] = arg
      lastIndex = index
    } else {
      result._.push(arg)
    }
  }

  return result
}

