  const result = { _: [] }

  let i = 0
  while (i < argv.length) {
    const arg = argv[i]

    if (arg.startsWith('-')) {
      const key = arg.slice(2)
      result[key] = true
      i += 1

      if (key.includes('=')) {
        const val = key.slice(key.indexOf('=') + 1)
        result[key.slice(0, key.indexOf('='))] = val
        i += 1
      } else if (i < argv.length && !argv[i].startsWith('-')) {
        result[key] = argv[i]
        i += 1
      }
    }

    i += 1
  }

  return result
}

