      if (hasEquals) {
        const eqIndex = key.indexOf('=')
        const k = key.slice(0, eqIndex)
        const val = key.slice(eqIndex + 1)
        result[k] = val
      } else if (i + 1 < argv.length && !argv[i + 1].startsWith('-')) {
        result[key] = argv[i + 1]
